#!/usr/bin/env python3
"""
Fix micro-variations in logo components.

This script:
1. Removes WORDMARK_NEUTRAL from Comete.tsx and updates the appearance logic
2. Replaces NEUTRAL text paths with BRAND paths in all product logos (DarkBody)
3. Removes leftover duplicate paths from LightBody in product logos
4. Unifies viewBoxes where BRAND_VB ≠ NEUTRAL_VB
5. Harmonizes product-specific text paths in OnTime.tsx DarkBody
"""

import re
from pathlib import Path

BASE_DIR = Path("/sessions/gallant-laughing-maxwell/mnt/GitHub/comete-logos/src/logos")

# ============================================================================
# TASK 1: Fix Comete.tsx - Remove WORDMARK_NEUTRAL
# ============================================================================

def fix_comete():
    """Remove WORDMARK_NEUTRAL and update appearance logic."""
    file_path = BASE_DIR / "Comete.tsx"
    content = file_path.read_text(encoding="utf-8")

    # Remove WORDMARK_NEUTRAL constant (lines 27-39)
    content = re.sub(
        r'const WORDMARK_NEUTRAL = \{[^}]*viewBox:.*?\],\n\};',
        '',
        content,
        flags=re.DOTALL
    )

    # Update line 204: change appearance ternary to always use BRAND
    old_line = 'const data = appearance === "brand" ? WORDMARK_BRAND : WORDMARK_NEUTRAL;'
    new_line = 'const data = WORDMARK_BRAND;'
    content = content.replace(old_line, new_line)

    file_path.write_text(content, encoding="utf-8")
    print(f"✓ Fixed Comete.tsx")


