def remove_duplicate_paths():
    """Remove extra duplicate paths from LightBody."""
    for filename, paths in PATHS_TO_REMOVE.items():
        file_path = BASE_DIR / filename
        if not file_path.exists():
            print(f"⚠ {filename} not found, skipping")
            continue

        content = file_path.read_text(encoding="utf-8")
        original_content = content

        for path_to_remove in paths:
            content = content.replace(path_to_remove + '\n', '')
            content = content.replace(path_to_remove, '')

        if content != original_content:
            file_path.write_text(content, encoding="utf-8")
            print(f"✓ Removed duplicate paths from {filename}")


def unify_viewboxes():
    """Unify BRAND_VB and NEUTRAL_VB where they differ."""
    viewbox_changes = {
        'Bi.tsx': ('0 0 186 32', '0 0 185 32'),
        'Link.tsx': ('0 0 218 32', '0 0 217 32'),
        'Mce.tsx': ('0 0 235 32', '0 0 234 32'),
    }

    for filename, (old_vb, new_vb) in viewbox_changes.items():
        file_path = BASE_DIR / filename
        if not file_path.exists():
            print(f"⚠ {filename} not found, skipping")
            continue

        content = file_path.read_text(encoding="utf-8")

        # Replace NEUTRAL_VB constant
        content = re.sub(
            f'const NEUTRAL_VB = "{old_vb}";',
            f'const NEUTRAL_VB = "{new_vb}";',
            content
        )

        # Replace the DarkBody SVG viewBox
        content = re.sub(
            f'viewBox={{{old_vb}}}',
            f'viewBox={{{new_vb}}}',
            content
        )

        file_path.write_text(content, encoding="utf-8")
        print(f"✓ Unified viewBox in {filename}")


def fix_ontime_product_text():
    """Replace DarkBody product text paths with LightBody versions in OnTime."""
    file_path = BASE_DIR / "OnTime.tsx"
    if not file_path.exists():
        print("⚠ OnTime.tsx not found, skipping")
        return

    content = file_path.read_text(encoding="utf-8")

    # Replacements for "on time" product text paths in DarkBody
